package gpipe

import (
	"bytes"
	"crypto/sha256"
	"fmt"
	"io"
	"io/fs"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
)

// Output holds the three generated file contents
type Output struct {
	InstallSh  string
	InstallPs1 string
	Checksums  string
}

// Generate produces install.sh, install.ps1, and checksums.txt from cfg
// tplFS must be an fs.FS with install.sh and install.ps1 at its root
// In dry-run mode, missing platform binary files produce warnings instead of errors
func Generate(cfg *Config, tplFS fs.FS, mode ValidationMode) (*Output, error) {
	shTpl, err := fs.ReadFile(tplFS, "install.sh")
	if err != nil {
		return nil, fmt.Errorf("reading install.sh template: %w", err)
	}
	ps1Tpl, err := fs.ReadFile(tplFS, "install.ps1")
	if err != nil {
		return nil, fmt.Errorf("reading install.ps1 template: %w", err)
	}

	checksums, err := buildChecksums(cfg, mode)
	if err != nil {
		return nil, err
	}

	preShHook, err := loadHook(cfg.Hooks.PreSh, "bash")
	if err != nil {
		return nil, fmt.Errorf("pre-sh hook: %w", err)
	}
	postShHook, err := loadHook(cfg.Hooks.PostSh, "bash")
	if err != nil {
		return nil, fmt.Errorf("post-sh hook: %w", err)
	}
	prePs1Hook, err := loadHook(cfg.Hooks.PrePs1, "ps1")
	if err != nil {
		return nil, fmt.Errorf("pre-ps1 hook: %w", err)
	}
	postPs1Hook, err := loadHook(cfg.Hooks.PostPs1, "ps1")
	if err != nil {
		return nil, fmt.Errorf("post-ps1 hook: %w", err)
	}

	sh, err := renderSh(string(shTpl), cfg, preShHook, postShHook)
	if err != nil {
		return nil, fmt.Errorf("rendering install.sh: %w", err)
	}

	ps1, err := renderPs1(string(ps1Tpl), cfg, prePs1Hook, postPs1Hook)
	if err != nil {
		return nil, fmt.Errorf("rendering install.ps1: %w", err)
	}

	return &Output{
		InstallSh:  sh,
		InstallPs1: ps1,
		Checksums:  checksums,
	}, nil
}

func buildChecksums(cfg *Config, mode ValidationMode) (string, error) {
	var sb strings.Builder
	for _, platform := range ValidPlatforms {
		path, ok := cfg.Platforms[platform]
		if !ok {
			continue
		}
		f, err := os.Open(path)
		if err != nil {
			if mode == ModeDryRun {
				fmt.Fprintf(os.Stderr, "warning: skipping checksum for %s: file not found at %s\n", platform, path)
				continue
			}
			return "", fmt.Errorf("opening binary for platform %s at %s: %w", platform, path, err)
		}
		h := sha256.New()
		if _, err := io.Copy(h, f); err != nil {
			f.Close()
			return "", fmt.Errorf("hashing binary for platform %s: %w", platform, err)
		}
		f.Close()
		assetName := filepath.Base(path)
		fmt.Fprintf(&sb, "%x  %s\n", h.Sum(nil), assetName)
	}
	return sb.String(), nil
}

func renderSh(tpl string, cfg *Config, preHook, postHook string) (string, error) {
	header := generatedByHeader(cfg)
	tpl = strings.ReplaceAll(tpl, "{{GPIPE_GENERATED_BY}}", header)
	tpl = strings.ReplaceAll(tpl, "{{GITHUB_REPO}}", cfg.GithubRepo)
	tpl = strings.ReplaceAll(tpl, "{{VERSION}}", cfg.Version)
	tpl = strings.ReplaceAll(tpl, "{{BINARY}}", cfg.Binary)
	tpl = strings.ReplaceAll(tpl, "{{INSTALL_NAME}}", cfg.InstallName)
	tpl = strings.ReplaceAll(tpl, "{{SUPPORTED_PLATFORMS_BLOCK}}", buildShSupportedPlatforms(cfg))
	tpl = strings.ReplaceAll(tpl, "{{ASSET_MAP_BLOCK}}", buildShAssetMap(cfg))
	tpl = injectOrRemoveHook(tpl, "{{PRE_INSTALL_HOOK}}", preHook, "pre-install", "bash")
	tpl = injectOrRemoveHook(tpl, "{{POST_INSTALL_HOOK}}", postHook, "post-install", "bash")
	tpl = conditionalBlock(tpl, "COMPLETION_BASH", cfg.Completions.Bash)
	tpl = conditionalBlock(tpl, "COMPLETION_ZSH", cfg.Completions.Zsh)
	tpl = conditionalBlock(tpl, "COMPLETION_FISH", cfg.Completions.Fish)
	return tpl, nil
}

func renderPs1(tpl string, cfg *Config, preHook, postHook string) (string, error) {
	header := generatedByHeader(cfg)
	tpl = strings.ReplaceAll(tpl, "{{GPIPE_GENERATED_BY}}", header)
	tpl = strings.ReplaceAll(tpl, "{{GITHUB_REPO}}", cfg.GithubRepo)
	tpl = strings.ReplaceAll(tpl, "{{VERSION}}", cfg.Version)
	tpl = strings.ReplaceAll(tpl, "{{BINARY}}", cfg.Binary)
	tpl = strings.ReplaceAll(tpl, "{{INSTALL_NAME}}", cfg.InstallName)
	tpl = strings.ReplaceAll(tpl, "{{SUPPORTED_PLATFORMS_BLOCK}}", buildPs1SupportedPlatforms(cfg))
	tpl = strings.ReplaceAll(tpl, "{{ASSET_MAP_BLOCK}}", buildPs1AssetMap(cfg))
	tpl = injectOrRemoveHook(tpl, "{{PRE_INSTALL_HOOK}}", preHook, "pre-install", "ps1")
	tpl = injectOrRemoveHook(tpl, "{{POST_INSTALL_HOOK}}", postHook, "post-install", "ps1")
	tpl = conditionalBlock(tpl, "COMPLETION_POWERSHELL", cfg.Completions.PowerShell)
	return tpl, nil
}

func generatedByHeader(cfg *Config) string {
	return fmt.Sprintf(
		"Generated by gpipe: https://github.com/thomaslaurenson/gpipe\n# Do not edit manually. Re-generate with: go run github.com/thomaslaurenson/gpipe generate --repo %s --version %s",
		cfg.GithubRepo, cfg.Version,
	)
}

func buildShSupportedPlatforms(cfg *Config) string {
	var platforms []string
	for _, p := range ValidPlatforms {
		if _, ok := cfg.Platforms[p]; ok {
			platforms = append(platforms, p)
		}
	}
	var sb strings.Builder
	sb.WriteString(fmt.Sprintf("SUPPORTED_PLATFORMS=(%s)\n", strings.Join(platforms, " ")))
	sb.WriteString(`_PLATFORM_OK=false
for _p in "${SUPPORTED_PLATFORMS[@]}"; do
  if [ "$_p" = "$PLATFORM" ]; then _PLATFORM_OK=true; break; fi
done
if [ "$_PLATFORM_OK" = "false" ]; then
  echo "error: unsupported platform ${PLATFORM}" >&2
  echo "  supported platforms: ${SUPPORTED_PLATFORMS[*]}" >&2
  exit 1
fi`)
	return sb.String()
}

func buildShAssetMap(cfg *Config) string {
	var sb strings.Builder
	sb.WriteString("declare -A ASSET_NAMES=(\n")
	for _, p := range ValidPlatforms {
		path, ok := cfg.Platforms[p]
		if !ok {
			continue
		}
		sb.WriteString(fmt.Sprintf("  [%s]=%q\n", p, filepath.Base(path)))
	}
	sb.WriteString(")")
	return sb.String()
}

func buildPs1SupportedPlatforms(cfg *Config) string {
	var platforms []string
	for _, p := range ValidPlatforms {
		if _, ok := cfg.Platforms[p]; ok {
			platforms = append(platforms, `"`+p+`"`)
		}
	}
	var sb strings.Builder
	sb.WriteString(fmt.Sprintf("$SupportedPlatforms = @(%s)\n", strings.Join(platforms, ", ")))
	sb.WriteString(`if ($SupportedPlatforms -notcontains $Platform) {
  Write-Error "Unsupported platform: $Platform. Supported: $($SupportedPlatforms -join ', ')"
  exit 1
}`)
	return sb.String()
}

func buildPs1AssetMap(cfg *Config) string {
	var sb strings.Builder
	sb.WriteString("$AssetNames = @{\n")
	for _, p := range ValidPlatforms {
		path, ok := cfg.Platforms[p]
		if !ok {
			continue
		}
		sb.WriteString(fmt.Sprintf("  \"%s\" = \"%s\"\n", p, filepath.Base(path)))
	}
	sb.WriteString("}")
	return sb.String()
}

func loadHook(path, shellType string) (string, error) {
	if path == "" {
		return "", nil
	}
	data, err := os.ReadFile(path)
	if err != nil {
		return "", fmt.Errorf("reading hook file %q: %w", path, err)
	}
	content := string(data)
	if strings.TrimSpace(content) == "" {
		fmt.Fprintf(os.Stderr, "warning: hook file %q is empty, skipping\n", path)
		return "", nil
	}
	if shellType == "bash" {
		if err := validateBashSyntax(path); err != nil {
			return "", err
		}
	}
	return content, nil
}

func validateBashSyntax(path string) error {
	bash, err := exec.LookPath("bash")
	if err != nil {
		fmt.Fprintf(os.Stderr, "warning: bash not found, skipping syntax check for %q\n", path)
		return nil
	}
	out, err := exec.Command(bash, "-n", path).CombinedOutput()
	if err != nil {
		return fmt.Errorf("bash syntax error in hook %q:\n%s", path, bytes.TrimSpace(out))
	}
	return nil
}

func injectOrRemoveHook(tpl, marker, content, label, shellType string) string {
	if content == "" {
		lines := strings.Split(tpl, "\n")
		var out []string
		for _, line := range lines {
			if strings.TrimSpace(line) == marker {
				continue
			}
			out = append(out, line)
		}
		return strings.Join(out, "\n")
	}

	var wrapped string
	switch shellType {
	case "bash":
		wrapped = fmt.Sprintf(
			"# --- gpipe: %s hook ---\n(\n%s\n)\n# --- gpipe: end %s hook ---",
			label, content, label,
		)
	case "ps1":
		wrapped = fmt.Sprintf(
			"# --- gpipe: %s hook ---\n& {\n%s\n}\n# --- gpipe: end %s hook ---",
			label, content, label,
		)
	}
	return strings.ReplaceAll(tpl, marker, wrapped)
}

func conditionalBlock(tpl, name string, keep bool) string {
	startMarker := "# BEGIN_BLOCK:" + name
	endMarker := "# END_BLOCK:" + name

	lines := strings.Split(tpl, "\n")
	var out []string
	inBlock := false
	for _, line := range lines {
		stripped := strings.TrimSpace(line)
		if stripped == startMarker {
			inBlock = true
			continue
		}
		if stripped == endMarker {
			inBlock = false
			continue
		}
		if inBlock && !keep {
			continue
		}
		out = append(out, line)
	}
	return strings.Join(out, "\n")
}
